#include "biblia.h"

void Biblia::CarregarRomanos(Biblia* b) {
    b->dados[ROMANOS].nome = wxT("Romanos");

    b->dados[ROMANOS].capitulos[1].versos[1] = wxT("Paulo, servo de Jesus Cristo, chamado para ser apóstolo, separado para o evangelho de Deus,");
    b->dados[ROMANOS].capitulos[1].versos[2] = wxT("que ele antes havia prometido pelos seus profetas nas santas Escrituras,");
    b->dados[ROMANOS].capitulos[1].versos[3] = wxT("acerca de seu Filho, que nasceu da descendência de Davi segundo a carne,");
    b->dados[ROMANOS].capitulos[1].versos[4] = wxT("e que com poder foi declarado Filho de Deus segundo o espírito de santidade, pela ressurreição dentre os mortos-Jesus Cristo nosso Senhor,");
    b->dados[ROMANOS].capitulos[1].versos[5] = wxT("pelo qual recebemos a graça e o apostolado, por amor do seu nome, para a obediência da fé entre todos os gentios,");
    b->dados[ROMANOS].capitulos[1].versos[6] = wxT("entre os quais sois também vós chamados para serdes de Jesus Cristo;");
    b->dados[ROMANOS].capitulos[1].versos[7] = wxT("a todos os que estais em Roma, amados de Deus, chamados para serdes santos: Graça a vós, e paz da parte de Deus nosso Pai, e do Senhor Jesus Cristo.");
    b->dados[ROMANOS].capitulos[1].versos[8] = wxT("Primeiramente dou graças ao meu Deus, mediante Jesus Cristo, por todos vós, porque em todo o mundo é anunciada a vossa fé.");
    b->dados[ROMANOS].capitulos[1].versos[9] = wxT("Pois Deus, a quem sirvo em meu espírito, no evangelho de seu Filho, me é testemunha de como incessantemente faço menção de vós,");
    b->dados[ROMANOS].capitulos[1].versos[10] = wxT("pedindo sempre em minhas orações que, afinal, pela vontade de Deus, se me ofereça boa ocasião para ir ter convosco.");
    b->dados[ROMANOS].capitulos[1].versos[11] = wxT("Porque desejo muito ver-vos, para vos comunicar algum dom espiritual, a fim de que sejais fortalecidos;");
    b->dados[ROMANOS].capitulos[1].versos[12] = wxT("isto é, para que juntamente convosco eu seja consolado em vós pela fé mútua, vossa e minha.");
    b->dados[ROMANOS].capitulos[1].versos[13] = wxT("E não quero que ignoreis, irmãos, que muitas vezes propus visitar-vos {mas até agora tenho sido impedido}, para conseguir algum fruto entre vós, como também entre os demais gentios.");
    b->dados[ROMANOS].capitulos[1].versos[14] = wxT("Eu sou devedor, tanto a gregos como a bárbaros, tanto a sábios como a ignorantes.");
    b->dados[ROMANOS].capitulos[1].versos[15] = wxT("De modo que, quanto está em mim, estou pronto para anunciar o evangelho também a vós que estais em Roma.");
    b->dados[ROMANOS].capitulos[1].versos[16] = wxT("Porque não me envergonho do evangelho, pois é o poder de Deus para salvação de todo aquele que crê; primeiro do judeu, e também do grego.");
    b->dados[ROMANOS].capitulos[1].versos[17] = wxT("Porque no evangelho é revelada, de fé em fé, a justiça de Deus, como está escrito: Mas o justo viverá da fé.");
    b->dados[ROMANOS].capitulos[1].versos[18] = wxT("Pois do céu é revelada a ira de Deus contra toda a impiedade e injustiça dos homens que detêm a verdade em injustiça.");
    b->dados[ROMANOS].capitulos[1].versos[19] = wxT("Porquanto, o que de Deus se pode conhecer, neles se manifesta, porque Deus lho manifestou.");
    b->dados[ROMANOS].capitulos[1].versos[20] = wxT("Pois os seus atributos invisíveis, o seu eterno poder e divindade, são claramente vistos desde a criação do mundo, sendo percebidos mediante as coisas criadas, de modo que eles são inescusáveis;");
    b->dados[ROMANOS].capitulos[1].versos[21] = wxT("porquanto, tendo conhecido a Deus, contudo não o glorificaram como Deus, nem lhe deram graças, antes nas suas especulações se desvaneceram, e o seu coração insensato se obscureceu.");
    b->dados[ROMANOS].capitulos[1].versos[22] = wxT("Dizendo-se sábios, tornaram-se estultos,");
    b->dados[ROMANOS].capitulos[1].versos[23] = wxT("e mudaram a glória do Deus incorruptível em semelhança da imagem de homem corruptível, e de aves, e de quadrúpedes, e de répteis.");
    b->dados[ROMANOS].capitulos[1].versos[24] = wxT("Por isso Deus os entregou, nas concupiscências de seus corações, à imundícia, para serem os seus corpos desonrados entre si;");
    b->dados[ROMANOS].capitulos[1].versos[25] = wxT("pois trocaram a verdade de Deus pela mentira, e adoraram e serviram à criatura antes que ao Criador, que é bendito eternamente. Amém.");
    b->dados[ROMANOS].capitulos[1].versos[26] = wxT("Pelo que Deus os entregou a paixões infames. Porque até as suas mulheres mudaram o uso natural no que é contrário à natureza;");
    b->dados[ROMANOS].capitulos[1].versos[27] = wxT("semelhantemente, também os varões, deixando o uso natural da mulher, se inflamaram em sua sensualidade uns para como os outros, varão com varão, cometendo torpeza e recebendo em si mesmos a devida recompensa do seu erro.");
    b->dados[ROMANOS].capitulos[1].versos[28] = wxT("E assim como eles rejeitaram o conhecimento de Deus, Deus, por sua vez, os entregou a um sentimento depravado, para fazerem coisas que não convêm;");
    b->dados[ROMANOS].capitulos[1].versos[29] = wxT("estando cheios de toda a injustiça, malícia, cobiça, maldade; cheios de inveja, homicídio, contenda, dolo, malignidade;");
    b->dados[ROMANOS].capitulos[1].versos[30] = wxT("sendo murmuradores, detratores, aborrecedores de Deus, injuriadores, soberbos, presunçosos, inventores de males, desobedientes ao pais;");
    b->dados[ROMANOS].capitulos[1].versos[31] = wxT("néscios, infiéis nos contratos, sem afeição natural, sem misericórdia;");
    b->dados[ROMANOS].capitulos[1].versos[32] = wxT("os quais, conhecendo bem o decreto de Deus, que declara dignos de morte os que tais coisas praticam, não somente as fazem, mas também aprovam os que as praticam.");

    b->dados[ROMANOS].capitulos[2].versos[1] = wxT("Portanto, és inescusável, ó homem, qualquer que sejas, quando julgas, porque te condenas a ti mesmo naquilo em que julgas a outro; pois tu que julgas, praticas o mesmo.");
    b->dados[ROMANOS].capitulos[2].versos[2] = wxT("E bem sabemos que o juízo de Deus é segundo a verdade, contra os que tais coisas praticam.");
    b->dados[ROMANOS].capitulos[2].versos[3] = wxT("E tu, ó homem, que julgas os que praticam tais coisas, cuidas que, fazendo-as tu, escaparás ao juízo de Deus?");
    b->dados[ROMANOS].capitulos[2].versos[4] = wxT("Ou desprezas tu as riquezas da sua benignidade, e paciência e longanimidade, ignorando que a benignidade de Deus te conduz ao arrependimento?");
    b->dados[ROMANOS].capitulos[2].versos[5] = wxT("Mas, segundo a tua dureza e teu coração impenitente, entesouras ira para ti no dia da ira e da revelação do justo juízo de Deus,");
    b->dados[ROMANOS].capitulos[2].versos[6] = wxT("que retribuirá a cada um segundo as suas obras;");
    b->dados[ROMANOS].capitulos[2].versos[7] = wxT("a saber: a vida eterna aos que, com perseverança em favor o bem, procuram glória, e honra e incorrupção;");
    b->dados[ROMANOS].capitulos[2].versos[8] = wxT("mas ira e indignação aos que são contenciosos, e desobedientes à iniqüidade;");
    b->dados[ROMANOS].capitulos[2].versos[9] = wxT("tribulação e angústia sobre a alma de todo homem que pratica o mal, primeiramente do judeu, e também do grego;");
    b->dados[ROMANOS].capitulos[2].versos[10] = wxT("glória, porém, e honra e paz a todo aquele que pratica o bem, primeiramente ao judeu, e também ao grego;");
    b->dados[ROMANOS].capitulos[2].versos[11] = wxT("pois para com Deus não há acepção de pessoas.");
    b->dados[ROMANOS].capitulos[2].versos[12] = wxT("Porque todos os que sem lei pecaram, sem lei também perecerão; e todos os que sob a lei pecaram, pela lei serão julgados.");
    b->dados[ROMANOS].capitulos[2].versos[13] = wxT("Pois não são justos diante de Deus os que só ouvem a lei; mas serão justificados os que praticam a lei");
    b->dados[ROMANOS].capitulos[2].versos[14] = wxT("{porque, quando os gentios, que não têm lei, fazem por natureza as coisas da lei, eles, embora não tendo lei, para si mesmos são lei.");
    b->dados[ROMANOS].capitulos[2].versos[15] = wxT("pois mostram a obra da lei escrita em seus corações, testificando juntamente a sua consciência e os seus pensamentos, quer acusando-os, quer defendendo-os},");
    b->dados[ROMANOS].capitulos[2].versos[16] = wxT("no dia em que Deus há de julgar os segredos dos homens, por Cristo Jesus, segundo o meu evangelho.");
    b->dados[ROMANOS].capitulos[2].versos[17] = wxT("Mas se tu és chamado judeu, e repousas na lei, e te glorias em Deus;");
    b->dados[ROMANOS].capitulos[2].versos[18] = wxT("e conheces a sua vontade e aprovas as coisas excelentes, sendo instruído na lei;");
    b->dados[ROMANOS].capitulos[2].versos[19] = wxT("e confias que és guia dos cegos, luz dos que estão em trevas,");
    b->dados[ROMANOS].capitulos[2].versos[20] = wxT("instruidor dos néscios, mestre de crianças, que tens na lei a forma da ciência e da verdade;");
    b->dados[ROMANOS].capitulos[2].versos[21] = wxT("tu, pois, que ensinas a outrem, não te ensinas a ti mesmo? Tu, que pregas que não se deve furtar, furtas?");
    b->dados[ROMANOS].capitulos[2].versos[22] = wxT("Tu, que dizes que não se deve cometer adultério, adulteras? Tu, que abominas os ídolos, roubas os templos?");
    b->dados[ROMANOS].capitulos[2].versos[23] = wxT("Tu, que te glorias na lei, desonras a Deus pela transgressão da lei?");
    b->dados[ROMANOS].capitulos[2].versos[24] = wxT("Assim pois, por vossa causa, o nome de Deus é blasfemado entre os gentios, como está escrito.");
    b->dados[ROMANOS].capitulos[2].versos[25] = wxT("Porque a circuncisão é, na verdade, proveitosa, se guardares a lei; mas se tu és transgressor da lei, a tua circuncisão tem-se tornado em incircuncisão.");
    b->dados[ROMANOS].capitulos[2].versos[26] = wxT("Se, pois, a incircuncisão guardar os preceitos da lei, porventura a incircuncisão não será reputada como circuncisão?");
    b->dados[ROMANOS].capitulos[2].versos[27] = wxT("E a incircuncisão que por natureza o é, se cumpre a lei, julgará a ti, que com a letra e a circuncisão és transgressor da lei.");
    b->dados[ROMANOS].capitulos[2].versos[28] = wxT("Porque não é judeu o que o é exteriormente, nem é circuncisão a que o é exteriormente na carne.");
    b->dados[ROMANOS].capitulos[2].versos[29] = wxT("Mas é judeu aquele que o é interiormente, e circuncisão é a do coração, no espírito, e não na letra; cujo louvor não provém dos homens, mas de Deus.");

    b->dados[ROMANOS].capitulos[3].versos[1] = wxT("Que vantagem, pois, tem o judeu? ou qual a utilidade da circuncisão?");
    b->dados[ROMANOS].capitulos[3].versos[2] = wxT("Muita, em todo sentido; primeiramente, porque lhe foram confiados os oráculos de Deus.");
    b->dados[ROMANOS].capitulos[3].versos[3] = wxT("Pois quê? Se alguns foram infiéis, porventura a sua infidelidade anulará a fidelidade de Deus?");
    b->dados[ROMANOS].capitulos[3].versos[4] = wxT("De modo nenhum; antes seja Deus verdadeiro, e todo homem mentiroso; como está escrito: Para que sejas justificado em tuas palavras, e venças quando fores julgado.");
    b->dados[ROMANOS].capitulos[3].versos[5] = wxT("E, se a nossa injustiça prova a justiça de Deus, que diremos? Acaso Deus, que castiga com ira, é injusto? {Falo como homem.}");
    b->dados[ROMANOS].capitulos[3].versos[6] = wxT("De modo nenhum; do contrário, como julgará Deus o mundo?");
    b->dados[ROMANOS].capitulos[3].versos[7] = wxT("Mas, se pela minha mentira abundou mais a verdade de Deus para sua glória, por que sou eu ainda julgado como pecador?");
    b->dados[ROMANOS].capitulos[3].versos[8] = wxT("E por que não dizemos: Façamos o mal para que venha o bem?-como alguns caluniosamente afirmam que dizemos; a condenação dos quais é justa.");
    b->dados[ROMANOS].capitulos[3].versos[9] = wxT("Pois quê? Somos melhores do que eles? De maneira nenhuma, pois já demonstramos que, tanto judeus como gregos, todos estão debaixo do pecado;");
    b->dados[ROMANOS].capitulos[3].versos[10] = wxT("como está escrito: Não há justo, nem sequer um.");
    b->dados[ROMANOS].capitulos[3].versos[11] = wxT("Não há quem entenda; não há quem busque a Deus.");
    b->dados[ROMANOS].capitulos[3].versos[12] = wxT("Todos se extraviaram; juntamente se fizeram inúteis. Não há quem faça o bem, não há nem um só.");
    b->dados[ROMANOS].capitulos[3].versos[13] = wxT("A sua garganta é um sepulcro aberto; com as suas línguas tratam enganosamente; peçonha de áspides está debaixo dos seus lábios;");
    b->dados[ROMANOS].capitulos[3].versos[14] = wxT("a sua boca está cheia de maldição e amargura.");
    b->dados[ROMANOS].capitulos[3].versos[15] = wxT("Os seus pés são ligeiros para derramar sangue.");
    b->dados[ROMANOS].capitulos[3].versos[16] = wxT("Nos seus caminhos há destruição e miséria;");
    b->dados[ROMANOS].capitulos[3].versos[17] = wxT("e não conheceram o caminho da paz.");
    b->dados[ROMANOS].capitulos[3].versos[18] = wxT("Não há temor de Deus diante dos seus olhos.");
    b->dados[ROMANOS].capitulos[3].versos[19] = wxT("Ora, nós sabemos que tudo o que a lei diz, aos que estão debaixo da lei o diz, para que se cale toda boca e todo o mundo fique sujeito ao juízo de Deus;");
    b->dados[ROMANOS].capitulos[3].versos[20] = wxT("porquanto pelas obras da lei nenhum homem será justificado diante dele; pois o que vem pela lei é o pleno conhecimento do pecado.");
    b->dados[ROMANOS].capitulos[3].versos[21] = wxT("Mas agora, sem lei, tem-se manifestado a justiça de Deus, que é atestada pela lei e pelos profetas;");
    b->dados[ROMANOS].capitulos[3].versos[22] = wxT("isto é, a justiça de Deus pela fé em Jesus Cristo para todos os que crêem; pois não há distinção.");
    b->dados[ROMANOS].capitulos[3].versos[23] = wxT("Porque todos pecaram e destituídos estão da glória de Deus;");
    b->dados[ROMANOS].capitulos[3].versos[24] = wxT("sendo justificados gratuitamente pela sua graça, mediante a redenção que há em Cristo Jesus,");
    b->dados[ROMANOS].capitulos[3].versos[25] = wxT("ao qual Deus propôs como propiciação, pela fé, no seu sangue, para demonstração da sua justiça por ter ele na sua paciência, deixado de lado os delitos outrora cometidos;");
    b->dados[ROMANOS].capitulos[3].versos[26] = wxT("para demonstração da sua justiça neste tempo presente, para que ele seja justo e também justificador daquele que tem fé em Jesus.");
    b->dados[ROMANOS].capitulos[3].versos[27] = wxT("Onde está logo a jactância? Foi excluída. Por que lei? Das obras? Não; mas pela lei da fé.");
    b->dados[ROMANOS].capitulos[3].versos[28] = wxT("concluímos pois que o homem é justificado pela fé sem as obras da lei.");
    b->dados[ROMANOS].capitulos[3].versos[29] = wxT("É porventura Deus somente dos judeus? Não é também dos gentios? Também dos gentios, certamente,");
    b->dados[ROMANOS].capitulos[3].versos[30] = wxT("se é que Deus é um só, que pela fé há de justificar a circuncisão, e também por meio da fé a incircuncisão.");
    b->dados[ROMANOS].capitulos[3].versos[31] = wxT("Anulamos, pois, a lei pela fé? De modo nenhum; antes estabelecemos a lei.");

    b->dados[ROMANOS].capitulos[4].versos[1] = wxT("Que diremos, pois, ter alcançado Abraão, nosso pai segundo a carne?");
    b->dados[ROMANOS].capitulos[4].versos[2] = wxT("Porque, se Abraão foi justificado pelas obras, tem de que se gloriar, mas não diante de Deus.");
    b->dados[ROMANOS].capitulos[4].versos[3] = wxT("Pois, que diz a Escritura? Creu Abraão a Deus, e isso lhe foi imputado como justiça.");
    b->dados[ROMANOS].capitulos[4].versos[4] = wxT("Ora, ao que trabalha não se lhe conta a recompensa como dádiva, mas sim como dívida;");
    b->dados[ROMANOS].capitulos[4].versos[5] = wxT("porém ao que não trabalha, mas crê naquele que justifica o ímpio, a sua fé lhe é contada como justiça;");
    b->dados[ROMANOS].capitulos[4].versos[6] = wxT("assim também Davi declara bem-aventurado o homem a quem Deus atribui a justiça sem as obras, dizendo:");
    b->dados[ROMANOS].capitulos[4].versos[7] = wxT("Bem-aventurados aqueles cujas iniqüidades são perdoadas, e cujos pecados são cobertos.");
    b->dados[ROMANOS].capitulos[4].versos[8] = wxT("Bem-aventurado o homem a quem o Senhor não imputará o pecado.");
    b->dados[ROMANOS].capitulos[4].versos[9] = wxT("Vem, pois, esta bem-aventurança sobre a circuncisão somente, ou também sobre a incircuncisão? Porque dizemos: A Abraão foi imputada a fé como justiça.");
    b->dados[ROMANOS].capitulos[4].versos[10] = wxT("Como, pois, lhe foi imputada? Estando na circuncisão, ou na incircuncisão? Não na circuncisão, mas sim na incircuncisão.");
    b->dados[ROMANOS].capitulos[4].versos[11] = wxT("E recebeu o sinal da circuncisão, selo da justiça da fé que teve quando ainda não era circuncidado, para que fosse pai de todos os que crêem, estando eles na incircuncisão, a fim de que a justiça lhes seja imputada,");
    b->dados[ROMANOS].capitulos[4].versos[12] = wxT("bem como fosse pai dos circuncisos, dos que não somente são da circuncisão, mas também andam nas pisadas daquela fé que teve nosso pai Abraão, antes de ser circuncidado.");
    b->dados[ROMANOS].capitulos[4].versos[13] = wxT("Porque não foi pela lei que veio a Abraão, ou à sua descendência, a promessa de que havia de ser herdeiro do mundo, mas pela justiça da fé.");
    b->dados[ROMANOS].capitulos[4].versos[14] = wxT("Pois, se os que são da lei são herdeiros, logo a fé é vã e a promessa é anulada.");
    b->dados[ROMANOS].capitulos[4].versos[15] = wxT("Porque a lei opera a ira; mas onde não há lei também não há transgressão.");
    b->dados[ROMANOS].capitulos[4].versos[16] = wxT("Porquanto procede da fé o ser herdeiro, para que seja segundo a graça, a fim de que a promessa seja firme a toda a descendência, não somente à que é da lei, mas também à que é da fé que teve Abraão, o qual é pai de todos nós.");
    b->dados[ROMANOS].capitulos[4].versos[17] = wxT("{como está escrito: Por pai de muitas nações te constituí} perante aquele no qual creu, a saber, Deus, que vivifica os mortos, e chama as coisas que não são, como se já fossem.");
    b->dados[ROMANOS].capitulos[4].versos[18] = wxT("O qual, em esperança, creu contra a esperança, para que se tornasse pai de muitas nações, conforme o que lhe fora dito: Assim será a tua descendência;");
    b->dados[ROMANOS].capitulos[4].versos[19] = wxT("e sem se enfraquecer na fé, considerou o seu próprio corpo já amortecido {pois tinha quase cem anos}, e o amortecimento do ventre de Sara;");
    b->dados[ROMANOS].capitulos[4].versos[20] = wxT("contudo, à vista da promessa de Deus, não vacilou por incredulidade, antes foi fortalecido na fé, dando glória a Deus,");
    b->dados[ROMANOS].capitulos[4].versos[21] = wxT("e estando certíssimo de que o que Deus tinha prometido, também era poderoso para o fazer.");
    b->dados[ROMANOS].capitulos[4].versos[22] = wxT("Pelo que também isso lhe foi imputado como justiça.");
    b->dados[ROMANOS].capitulos[4].versos[23] = wxT("Ora, não é só por causa dele que está escrito que lhe foi imputado;");
    b->dados[ROMANOS].capitulos[4].versos[24] = wxT("mas também por causa de nós a quem há de ser imputado, a nós os que cremos naquele que dos mortos ressuscitou a Jesus nosso Senhor;");
    b->dados[ROMANOS].capitulos[4].versos[25] = wxT("o qual foi entregue por causa das nossas transgressões, e ressuscitado para a nossa justificação.");

    b->dados[ROMANOS].capitulos[5].versos[1] = wxT("Justificados, pois, pela fé, tenhamos paz com Deus, por nosso Senhor Jesus Cristo,");
    b->dados[ROMANOS].capitulos[5].versos[2] = wxT("por quem obtivemos também nosso acesso pela fé a esta graça, na qual estamos firmes, e gloriemo-nos na esperança da glória de Deus.");
    b->dados[ROMANOS].capitulos[5].versos[3] = wxT("E não somente isso, mas também gloriemo-nos nas tribulações; sabendo que a tribulação produz a perseverança,");
    b->dados[ROMANOS].capitulos[5].versos[4] = wxT("e a perseverança a experiência, e a experiência a esperança;");
    b->dados[ROMANOS].capitulos[5].versos[5] = wxT("e a esperança não desaponta, porquanto o amor de Deus está derramado em nossos corações pelo Espírito Santo que nos foi dado.");
    b->dados[ROMANOS].capitulos[5].versos[6] = wxT("Pois, quando ainda éramos fracos, Cristo morreu a seu tempo pelos ímpios.");
    b->dados[ROMANOS].capitulos[5].versos[7] = wxT("Porque dificilmente haverá quem morra por um justo; pois poderá ser que pelo homem bondoso alguém ouse morrer.");
    b->dados[ROMANOS].capitulos[5].versos[8] = wxT("Mas Deus dá prova do seu amor para conosco, em que, quando éramos ainda pecadores, Cristo morreu por nós.");
    b->dados[ROMANOS].capitulos[5].versos[9] = wxT("Logo muito mais, sendo agora justificados pelo seu sangue, seremos por ele salvos da ira.");
    b->dados[ROMANOS].capitulos[5].versos[10] = wxT("Porque se nós, quando éramos inimigos, fomos reconciliados com Deus pela morte de seu Filho, muito mais, estando já reconciliados, seremos salvos pela sua vida.");
    b->dados[ROMANOS].capitulos[5].versos[11] = wxT("E não somente isso, mas também nos gloriamos em Deus por nosso Senhor Jesus Cristo, pelo qual agora temos recebido a reconciliação.");
    b->dados[ROMANOS].capitulos[5].versos[12] = wxT("Portanto, assim como por um só homem entrou o pecado no mundo, e pelo pecado a morte, assim também a morte passou a todos os homens, porquanto todos pecaram.");
    b->dados[ROMANOS].capitulos[5].versos[13] = wxT("Porque antes da lei já estava o pecado no mundo, mas onde não há lei o pecado não é levado em conta.");
    b->dados[ROMANOS].capitulos[5].versos[14] = wxT("No entanto a morte reinou desde Adão até Moisés, mesmo sobre aqueles que não pecaram à semelhança da transgressão de Adão o qual é figura daquele que havia de vir.");
    b->dados[ROMANOS].capitulos[5].versos[15] = wxT("Mas não é assim o dom gratuito como a ofensa; porque, se pela ofensa de um morreram muitos, muito mais a graça de Deus, e o dom pela graça de um só homem, Jesus Cristo, abundou para com muitos.");
    b->dados[ROMANOS].capitulos[5].versos[16] = wxT("Também não é assim o dom como a ofensa, que veio por um só que pecou; porque o juízo veio, na verdade, de uma só ofensa para condenação, mas o dom gratuito veio de muitas ofensas para justificação.");
    b->dados[ROMANOS].capitulos[5].versos[17] = wxT("Porque, se pela ofensa de um só, a morte veio a reinar por esse, muito mais os que recebem a abundância da graça, e do dom da justiça, reinarão em vida por um só, Jesus Cristo.");
    b->dados[ROMANOS].capitulos[5].versos[18] = wxT("Portanto, assim como por uma só ofensa veio o juízo sobre todos os homens para condenação, assim também por um só ato de justiça veio a graça sobre todos os homens para justificação e vida.");
    b->dados[ROMANOS].capitulos[5].versos[19] = wxT("Porque, assim como pela desobediência de um só homem muitos foram constituídos pecadores, assim também pela obediência de um muitos serão constituídos justos.");
    b->dados[ROMANOS].capitulos[5].versos[20] = wxT("Sobreveio, porém, a lei para que a ofensa abundasse; mas, onde o pecado abundou, superabundou a graça;");
    b->dados[ROMANOS].capitulos[5].versos[21] = wxT("para que, assim como o pecado veio a reinar na morte, assim também viesse a reinar a graça pela justiça para a vida eterna, por Jesus Cristo nosso Senhor.");

    b->dados[ROMANOS].capitulos[6].versos[1] = wxT("Que diremos, pois? Permaneceremos no pecado, para que abunde a graça?");
    b->dados[ROMANOS].capitulos[6].versos[2] = wxT("De modo nenhum. Nós, que já morremos para o pecado, como viveremos ainda nele?");
    b->dados[ROMANOS].capitulos[6].versos[3] = wxT("Ou, porventura, ignorais que todos quantos fomos batizados em Cristo Jesus fomos batizados na sua morte?");
    b->dados[ROMANOS].capitulos[6].versos[4] = wxT("Fomos, pois, sepultados com ele pelo batismo na morte, para que, como Cristo foi ressuscitado dentre os mortos pela glória do Pai, assim andemos nós também em novidade de vida.");
    b->dados[ROMANOS].capitulos[6].versos[5] = wxT("Porque, se temos sido unidos a ele na semelhança da sua morte, certamente também o seremos na semelhança da sua ressurreição;");
    b->dados[ROMANOS].capitulos[6].versos[6] = wxT("sabendo isto, que o nosso homem velho foi crucificado com ele, para que o corpo do pecado fosse desfeito, a fim de não servirmos mais ao pecado.");
    b->dados[ROMANOS].capitulos[6].versos[7] = wxT("Pois quem está morto está justificado do pecado.");
    b->dados[ROMANOS].capitulos[6].versos[8] = wxT("Ora, se já morremos com Cristo, cremos que também com ele viveremos,");
    b->dados[ROMANOS].capitulos[6].versos[9] = wxT("sabendo que, tendo Cristo ressurgido dentre os mortos, já não morre mais; a morte não mais tem domínio sobre ele.");
    b->dados[ROMANOS].capitulos[6].versos[10] = wxT("Pois quanto a ter morrido, de uma vez por todas morreu para o pecado, mas quanto a viver, vive para Deus.");
    b->dados[ROMANOS].capitulos[6].versos[11] = wxT("Assim também vós considerai-vos como mortos para o pecado, mas vivos para Deus, em Cristo Jesus.");
    b->dados[ROMANOS].capitulos[6].versos[12] = wxT("Não reine, portanto, o pecado em vosso corpo mortal, para obedecerdes às suas concupiscências;");
    b->dados[ROMANOS].capitulos[6].versos[13] = wxT("nem tampouco apresenteis os vossos membros ao pecado como instrumentos de iniqüidade; mas apresentai-vos a Deus, como redivivos dentre os mortos, e os vossos membros a Deus, como instrumentos de justiça.");
    b->dados[ROMANOS].capitulos[6].versos[14] = wxT("Pois o pecado não terá domínio sobre vós, porquanto não estais debaixo da lei, mas debaixo da graça.");
    b->dados[ROMANOS].capitulos[6].versos[15] = wxT("Pois quê? Havemos de pecar porque não estamos debaixo da lei, mas debaixo da graça? De modo nenhum.");
    b->dados[ROMANOS].capitulos[6].versos[16] = wxT("Não sabeis que daquele a quem vos apresentais como servos para lhe obedecer, sois servos desse mesmo a quem obedeceis, seja do pecado para a morte, ou da obediência para a justiça?");
    b->dados[ROMANOS].capitulos[6].versos[17] = wxT("Mas graças a Deus que, embora tendo sido servos do pecado, obedecestes de coração à forma de doutrina a que fostes entregues;");
    b->dados[ROMANOS].capitulos[6].versos[18] = wxT("e libertos do pecado, fostes feitos servos da justiça.");
    b->dados[ROMANOS].capitulos[6].versos[19] = wxT("Falo como homem, por causa da fraqueza da vossa carne. Pois assim como apresentastes os vossos membros como servos da impureza e da iniqüidade para iniqüidade, assim apresentai agora os vossos membros como servos da justiça para santificação.");
    b->dados[ROMANOS].capitulos[6].versos[20] = wxT("Porque, quando éreis servos do pecado, estáveis livres em relação à justiça.");
    b->dados[ROMANOS].capitulos[6].versos[21] = wxT("E que fruto tínheis então das coisas de que agora vos envergonhais? pois o fim delas é a morte.");
    b->dados[ROMANOS].capitulos[6].versos[22] = wxT("Mas agora, libertos do pecado, e feitos servos de Deus, tendes o vosso fruto para santificação, e por fim a vida eterna.");
    b->dados[ROMANOS].capitulos[6].versos[23] = wxT("Porque o salário do pecado é a morte, mas o dom gratuito de Deus é a vida eterna em Cristo Jesus nosso Senhor.");

    b->dados[ROMANOS].capitulos[7].versos[1] = wxT("Ou ignorais, irmãos {pois falo aos que conhecem a lei}, que a lei tem domínio sobre o homem por todo o tempo que ele vive?");
    b->dados[ROMANOS].capitulos[7].versos[2] = wxT("Porque a mulher casada está ligada pela lei a seu marido enquanto ele viver; mas, se ele morrer, ela está livre da lei do marido.");
    b->dados[ROMANOS].capitulos[7].versos[3] = wxT("De sorte que, enquanto viver o marido, será chamado adúltera, se for de outro homem; mas, se ele morrer, ela está livre da lei, e assim não será adúltera se for de outro marido.");
    b->dados[ROMANOS].capitulos[7].versos[4] = wxT("Assim também vós, meus irmãos, fostes mortos quanto à lei mediante o corpo de Cristo, para pertencerdes a outro, àquele que ressurgiu dentre os mortos a fim de que demos fruto para Deus.");
    b->dados[ROMANOS].capitulos[7].versos[5] = wxT("Pois, quando estávamos na carne, as paixões dos pecados, suscitadas pela lei, operavam em nossos membros para darem fruto para a morte.");
    b->dados[ROMANOS].capitulos[7].versos[6] = wxT("Mas agora fomos libertos da lei, havendo morrido para aquilo em que estávamos retidos, para servirmos em novidade de espírito, e não na velhice da letra.");
    b->dados[ROMANOS].capitulos[7].versos[7] = wxT("Que diremos pois? É a lei pecado? De modo nenhum. Contudo, eu não conheci o pecado senão pela lei; porque eu não conheceria a concupiscência, se a lei não dissesse: Não cobiçarás.");
    b->dados[ROMANOS].capitulos[7].versos[8] = wxT("Mas o pecado, tomando ocasião, pelo mandamento operou em mim toda espécie de concupiscência; porquanto onde não há lei está morto o pecado.");
    b->dados[ROMANOS].capitulos[7].versos[9] = wxT("E outrora eu vivia sem a lei; mas assim que veio o mandamento, reviveu o pecado, e eu morri;");
    b->dados[ROMANOS].capitulos[7].versos[10] = wxT("e o mandamento que era para vida, esse achei que me era para morte.");
    b->dados[ROMANOS].capitulos[7].versos[11] = wxT("Porque o pecado, tomando ocasião, pelo mandamento me enganou, e por ele me matou.");
    b->dados[ROMANOS].capitulos[7].versos[12] = wxT("De modo que a lei é santa, e o mandamento santo, justo e bom.");
    b->dados[ROMANOS].capitulos[7].versos[13] = wxT("Logo o bom tornou-se morte para mim? De modo nenhum; mas o pecado, para que se mostrasse pecado, operou em mim a morte por meio do bem; a fim de que pelo mandamento o pecado se manifestasse excessivamente maligno.");
    b->dados[ROMANOS].capitulos[7].versos[14] = wxT("Porque bem sabemos que a lei é espiritual; mas eu sou carnal, vendido sob o pecado.");
    b->dados[ROMANOS].capitulos[7].versos[15] = wxT("Pois o que faço, não o entendo; porque o que quero, isso não pratico; mas o que aborreço, isso faço.");
    b->dados[ROMANOS].capitulos[7].versos[16] = wxT("E, se faço o que não quero, consinto com a lei, que é boa.");
    b->dados[ROMANOS].capitulos[7].versos[17] = wxT("Agora, porém, não sou mais eu que faço isto, mas o pecado que habita em mim.");
    b->dados[ROMANOS].capitulos[7].versos[18] = wxT("Porque eu sei que em mim, isto é, na minha carne, não habita bem algum; com efeito o querer o bem está em mim, mas o efetuá-lo não está.");
    b->dados[ROMANOS].capitulos[7].versos[19] = wxT("Pois não faço o bem que quero, mas o mal que não quero, esse pratico.");
    b->dados[ROMANOS].capitulos[7].versos[20] = wxT("Ora, se eu faço o que não quero, já o não faço eu, mas o pecado que habita em mim.");
    b->dados[ROMANOS].capitulos[7].versos[21] = wxT("Acho então esta lei em mim, que, mesmo querendo eu fazer o bem, o mal está comigo.");
    b->dados[ROMANOS].capitulos[7].versos[22] = wxT("Porque, segundo o homem interior, tenho prazer na lei de Deus;");
    b->dados[ROMANOS].capitulos[7].versos[23] = wxT("mas vejo nos meus membros outra lei guerreando contra a lei do meu entendimento, e me levando cativo à lei do pecado, que está nos meus membros.");
    b->dados[ROMANOS].capitulos[7].versos[24] = wxT("Miserável homem que eu sou! quem me livrará do corpo desta morte?");
    b->dados[ROMANOS].capitulos[7].versos[25] = wxT("Graças a Deus, por Jesus Cristo nosso Senhor! De modo que eu mesmo com o entendimento sirvo à lei de Deus, mas com a carne à lei do pecado.");

    b->dados[ROMANOS].capitulos[8].versos[1] = wxT("Portanto, agora nenhuma condenação há para os que estão em Cristo Jesus.");
    b->dados[ROMANOS].capitulos[8].versos[2] = wxT("Porque a lei do Espírito da vida, em Cristo Jesus, te livrou da lei do pecado e da morte.");
    b->dados[ROMANOS].capitulos[8].versos[3] = wxT("Porquanto o que era impossível à lei, visto que se achava fraca pela carne, Deus enviando o seu próprio Filho em semelhança da carne do pecado, e por causa do pecado, na carne condenou o pecado.");
    b->dados[ROMANOS].capitulos[8].versos[4] = wxT("para que a justa exigência da lei se cumprisse em nós, que não andamos segundo a carne, mas segundo o Espírito.");
    b->dados[ROMANOS].capitulos[8].versos[5] = wxT("Pois os que são segundo a carne inclinam-se para as coisas da carne; mas os que são segundo o Espírito para as coisas do Espírito.");
    b->dados[ROMANOS].capitulos[8].versos[6] = wxT("Porque a inclinação da carne é morte; mas a inclinação do Espírito é vida e paz.");
    b->dados[ROMANOS].capitulos[8].versos[7] = wxT("Porquanto a inclinação da carne é inimizade contra Deus, pois não é sujeita à lei de Deus, nem em verdade o pode ser;");
    b->dados[ROMANOS].capitulos[8].versos[8] = wxT("e os que estão na carne não podem agradar a Deus.");
    b->dados[ROMANOS].capitulos[8].versos[9] = wxT("Vós, porém, não estais na carne, mas no Espírito, se é que o Espírito de Deus habita em vós. Mas, se alguém não tem o Espírito de Cristo, esse tal não é dele.");
    b->dados[ROMANOS].capitulos[8].versos[10] = wxT("Ora, se Cristo está em vós, o corpo, na verdade, está morto por causa do pecado, mas o espírito vive por causa da justiça.");
    b->dados[ROMANOS].capitulos[8].versos[11] = wxT("E, se o Espírito daquele que dos mortos ressuscitou a Jesus habita em vós, aquele que dos mortos ressuscitou a Cristo Jesus há de vivificar também os vossos corpos mortais, pelo seu Espírito que em vós habita.");
    b->dados[ROMANOS].capitulos[8].versos[12] = wxT("Portanto, irmãos, somos devedores, não à carne para vivermos segundo a carne;");
    b->dados[ROMANOS].capitulos[8].versos[13] = wxT("porque se viverdes segundo a carne, haveis de morrer; mas, se pelo Espírito mortificardes as obras do corpo, vivereis.");
    b->dados[ROMANOS].capitulos[8].versos[14] = wxT("Pois todos os que são guiados pelo Espírito de Deus, esses são filhos de Deus.");
    b->dados[ROMANOS].capitulos[8].versos[15] = wxT("Porque não recebestes o espírito de escravidão, para outra vez estardes com temor, mas recebestes o espírito de adoção, pelo qual clamamos: Aba, Pai!");
    b->dados[ROMANOS].capitulos[8].versos[16] = wxT("O Espírito mesmo testifica com o nosso espírito que somos filhos de Deus;");
    b->dados[ROMANOS].capitulos[8].versos[17] = wxT("e, se filhos, também herdeiros, herdeiros de Deus e co-herdeiros de Cristo; se é certo que com ele padecemos, para que também com ele sejamos glorificados.");
    b->dados[ROMANOS].capitulos[8].versos[18] = wxT("Pois tenho para mim que as aflições deste tempo presente não se podem comparar com a glória que em nós há de ser revelada.");
    b->dados[ROMANOS].capitulos[8].versos[19] = wxT("Porque a criação aguarda com ardente expectativa a revelação dos filhos de Deus.");
    b->dados[ROMANOS].capitulos[8].versos[20] = wxT("Porquanto a criação ficou sujeita à vaidade, não por sua vontade, mas por causa daquele que a sujeitou,");
    b->dados[ROMANOS].capitulos[8].versos[21] = wxT("na esperança de que também a própria criação há de ser liberta do cativeiro da corrupção, para a liberdade da glória dos filhos de Deus.");
    b->dados[ROMANOS].capitulos[8].versos[22] = wxT("Porque sabemos que toda a criação, conjuntamente, geme e está com dores de parto até agora;");
    b->dados[ROMANOS].capitulos[8].versos[23] = wxT("e não só ela, mas até nós, que temos as primícias do Espírito, também gememos em nós mesmos, aguardando a nossa adoração, a saber, a redenção do nosso corpo.");
    b->dados[ROMANOS].capitulos[8].versos[24] = wxT("Porque na esperança fomos salvos. Ora, a esperança que se vê não é esperança; pois o que alguém vê, como o espera?");
    b->dados[ROMANOS].capitulos[8].versos[25] = wxT("Mas, se esperamos o que não vemos, com paciência o aguardamos.");
    b->dados[ROMANOS].capitulos[8].versos[26] = wxT("Do mesmo modo também o Espírito nos ajuda na fraqueza; porque não sabemos o que havemos de pedir como convém, mas o Espírito mesmo intercede por nós com gemidos inexprimíveis.");
    b->dados[ROMANOS].capitulos[8].versos[27] = wxT("E aquele que esquadrinha os corações sabe qual é a intenção do Espírito: que ele, segundo a vontade de Deus, intercede pelos santos.");
    b->dados[ROMANOS].capitulos[8].versos[28] = wxT("E sabemos que todas as coisas concorrem para o bem daqueles que amam a Deus, daqueles que são chamados segundo o seu propósito.");
    b->dados[ROMANOS].capitulos[8].versos[29] = wxT("Porque os que dantes conheceu, também os predestinou para serem conformes à imagem de seu Filho, a fim de que ele seja o primogênito entre muitos irmãos;");
    b->dados[ROMANOS].capitulos[8].versos[30] = wxT("e aos que predestinou, a estes também chamou; e aos que chamou, a estes também justificou; e aos que justificou, a estes também glorificou.");
    b->dados[ROMANOS].capitulos[8].versos[31] = wxT("Que diremos, pois, a estas coisas? Se Deus é por nós, quem será contra nós?");
    b->dados[ROMANOS].capitulos[8].versos[32] = wxT("Aquele que nem mesmo a seu próprio Filho poupou, antes o entregou por todos nós, como não nos dará também com ele todas as coisas?");
    b->dados[ROMANOS].capitulos[8].versos[33] = wxT("Quem intentará acusação contra os escolhidos de Deus? É Deus quem os justifica;");
    b->dados[ROMANOS].capitulos[8].versos[34] = wxT("Quem os condenará? Cristo Jesus é quem morreu, ou antes quem ressurgiu dentre os mortos, o qual está à direita de Deus, e também intercede por nós;");
    b->dados[ROMANOS].capitulos[8].versos[35] = wxT("quem nos separará do amor de Cristo? a tribulação, ou a angústia, ou a perseguição, ou a fome, ou a nudez, ou o perigo, ou a espada?");
    b->dados[ROMANOS].capitulos[8].versos[36] = wxT("Como está escrito: Por amor de ti somos entregues à morte o dia todo; fomos considerados como ovelhas para o matadouro.");
    b->dados[ROMANOS].capitulos[8].versos[37] = wxT("Mas em todas estas coisas somos mais que vencedores, por aquele que nos amou.");
    b->dados[ROMANOS].capitulos[8].versos[38] = wxT("Porque estou certo de que, nem a morte, nem a vida, nem anjos, nem principados, nem coisas presentes, nem futuras, nem potestades,");
    b->dados[ROMANOS].capitulos[8].versos[39] = wxT("nem a altura, nem a profundidade, nem qualquer outra criatura nos poderá separar do amor de Deus, que está em Cristo Jesus nosso Senhor.");

    b->dados[ROMANOS].capitulos[9].versos[1] = wxT("Digo a verdade em Cristo, não minto, dando testemunho comigo a minha consciência no Espírito Santo,");
    b->dados[ROMANOS].capitulos[9].versos[2] = wxT("que tenho grande tristeza e incessante dor no meu coração.");
    b->dados[ROMANOS].capitulos[9].versos[3] = wxT("Porque eu mesmo desejaria ser separado de Cristo, por amor de meus irmãos, que são meus parentes segundo a carne;");
    b->dados[ROMANOS].capitulos[9].versos[4] = wxT("os quais são israelitas, de quem é a adoção, e a glória, e os pactos, e a promulgação da lei, e o culto, e as promessas;");
    b->dados[ROMANOS].capitulos[9].versos[5] = wxT("de quem são os patriarcas; e de quem descende o Cristo segundo a carne, o qual é sobre todas as coisas, Deus bendito eternamente. Amém.");
    b->dados[ROMANOS].capitulos[9].versos[6] = wxT("Não que a palavra de Deus haja falhado. Porque nem todos os que são de Israel são israelitas;");
    b->dados[ROMANOS].capitulos[9].versos[7] = wxT("nem por serem descendência de Abraão são todos filhos; mas: Em Isaque será chamada a tua descendência.");
    b->dados[ROMANOS].capitulos[9].versos[8] = wxT("Isto é, não são os filhos da carne que são filhos de Deus; mas os filhos da promessa são contados como descendência.");
    b->dados[ROMANOS].capitulos[9].versos[9] = wxT("Porque a palavra da promessa é esta: Por este tempo virei, e Sara terá um filho.");
    b->dados[ROMANOS].capitulos[9].versos[10] = wxT("E não somente isso, mas também a Rebeca, que havia concebido de um, de Isaque, nosso pai");
    b->dados[ROMANOS].capitulos[9].versos[11] = wxT("{pois não tendo os gêmeos ainda nascido, nem tendo praticado bem ou mal, para que o propósito de Deus segundo a eleição permanecesse firme, não por causa das obras, mas por aquele que chama},");
    b->dados[ROMANOS].capitulos[9].versos[12] = wxT("foi-lhe dito: O maior servirá o menor.");
    b->dados[ROMANOS].capitulos[9].versos[13] = wxT("Como está escrito: Amei a Jacó, e aborreci a Esaú.");
    b->dados[ROMANOS].capitulos[9].versos[14] = wxT("Que diremos, pois? Há injustiça da parte de Deus? De modo nenhum.");
    b->dados[ROMANOS].capitulos[9].versos[15] = wxT("Porque diz a Moisés: Terei misericórdia de quem me aprouver ter misericórdia, e terei compaixão de quem me aprouver ter compaixão.");
    b->dados[ROMANOS].capitulos[9].versos[16] = wxT("Assim, pois, isto não depende do que quer, nem do que corre, mas de Deus que usa de misericórdia.");
    b->dados[ROMANOS].capitulos[9].versos[17] = wxT("Pois diz a Escritura a Faraó: Para isto mesmo te levantei: para em ti mostrar o meu poder, e para que seja anunciado o meu nome em toda a terra.");
    b->dados[ROMANOS].capitulos[9].versos[18] = wxT("Portanto, tem misericórdia de quem quer, e a quem quer endurece.");
    b->dados[ROMANOS].capitulos[9].versos[19] = wxT("Dir-me-ás então. Por que se queixa ele ainda? Pois, quem resiste à sua vontade?");
    b->dados[ROMANOS].capitulos[9].versos[20] = wxT("Mas, ó homem, quem és tu, que a Deus replicas? Porventura a coisa formada dirá ao que a formou: Por que me fizeste assim?");
    b->dados[ROMANOS].capitulos[9].versos[21] = wxT("Ou não tem o oleiro poder sobre o barro, para da mesma massa fazer um vaso para uso honroso e outro para uso desonroso?");
    b->dados[ROMANOS].capitulos[9].versos[22] = wxT("E que direis, se Deus, querendo mostrar a sua ira, e dar a conhecer o seu poder, suportou com muita paciência os vasos da ira, preparados para a perdição;");
    b->dados[ROMANOS].capitulos[9].versos[23] = wxT("para que também desse a conhecer as riquezas da sua glória nos vasos de misericórdia, que de antemão preparou para a glória,");
    b->dados[ROMANOS].capitulos[9].versos[24] = wxT("os quais somos nós, a quem também chamou, não só dentre os judeus, mas também dentre os gentios?");
    b->dados[ROMANOS].capitulos[9].versos[25] = wxT("Como diz ele também em Oséias: Chamarei meu povo ao que não era meu povo; e amada à que não era amada.");
    b->dados[ROMANOS].capitulos[9].versos[26] = wxT("E sucederá que no lugar em que lhes foi dito: Vós não sois meu povo; aí serão chamados filhos do Deus vivo.");
    b->dados[ROMANOS].capitulos[9].versos[27] = wxT("Também Isaías exclama acerca de Israel: Ainda que o número dos filhos de Israel seja como a areia do mar, o remanescente é que será salvo.");
    b->dados[ROMANOS].capitulos[9].versos[28] = wxT("Porque o Senhor executará a sua palavra sobre a terra, consumando-a e abreviando-a.");
    b->dados[ROMANOS].capitulos[9].versos[29] = wxT("E como antes dissera Isaías: Se o Senhor dos Exércitos não nos tivesse deixado descendência, teríamos sido feitos como Sodoma, e seríamos semelhantes a Gomorra.");
    b->dados[ROMANOS].capitulos[9].versos[30] = wxT("Que diremos pois? Que os gentios, que não buscavam a justiça, alcançaram a justiça, mas a justiça que vem da fé.");
    b->dados[ROMANOS].capitulos[9].versos[31] = wxT("Mas Israel, buscando a lei da justiça, não atingiu esta lei.");
    b->dados[ROMANOS].capitulos[9].versos[32] = wxT("Por que? Porque não a buscavam pela fé, mas como que pelas obras; e tropeçaram na pedra de tropeço;");
    b->dados[ROMANOS].capitulos[9].versos[33] = wxT("como está escrito: Eis que eu ponho em Sião uma pedra de tropeço; e uma rocha de escândalo; e quem nela crer não será confundido.");

    b->dados[ROMANOS].capitulos[10].versos[1] = wxT("Irmãos, o bom desejo do meu coração e a minha súplica a Deus por Israel é para sua salvação.");
    b->dados[ROMANOS].capitulos[10].versos[2] = wxT("Porque lhes dou testemunho de que têm zelo por Deus, mas não com entendimento.");
    b->dados[ROMANOS].capitulos[10].versos[3] = wxT("Porquanto, não conhecendo a justiça de Deus, e procurando estabelecer a sua própria, não se sujeitaram à justiça de Deus.");
    b->dados[ROMANOS].capitulos[10].versos[4] = wxT("Pois Cristo é o fim da lei para justificar a todo aquele que crê.");
    b->dados[ROMANOS].capitulos[10].versos[5] = wxT("Porque Moisés escreve que o homem que pratica a justiça que vem da lei viverá por ela.");
    b->dados[ROMANOS].capitulos[10].versos[6] = wxT("Mas a justiça que vem da fé diz assim: Não digas em teu coração: Quem subirá ao céu? {isto é, a trazer do alto a Cristo;}");
    b->dados[ROMANOS].capitulos[10].versos[7] = wxT("ou: Quem descerá ao abismo? {isto é, a fazer subir a Cristo dentre os mortos}.");
    b->dados[ROMANOS].capitulos[10].versos[8] = wxT("Mas que diz? A palavra está perto de ti, na tua boca e no teu coração; isto é, a palavra da fé, que pregamos.");
    b->dados[ROMANOS].capitulos[10].versos[9] = wxT("Porque, se com a tua boca confessares a Jesus como Senhor, e em teu coração creres que Deus o ressuscitou dentre os mortos, será salvo;");
    b->dados[ROMANOS].capitulos[10].versos[10] = wxT("pois é com o coração que se crê para a justiça, e com a boca se faz confissão para a salvação.");
    b->dados[ROMANOS].capitulos[10].versos[11] = wxT("Porque a Escritura diz: Ninguém que nele crê será confundido.");
    b->dados[ROMANOS].capitulos[10].versos[12] = wxT("Porquanto não há distinção entre judeu e grego; porque o mesmo Senhor o é de todos, rico para com todos os que o invocam.");
    b->dados[ROMANOS].capitulos[10].versos[13] = wxT("Porque: Todo aquele que invocar o nome do Senhor será salvo.");
    b->dados[ROMANOS].capitulos[10].versos[14] = wxT("Como pois invocarão aquele em quem não creram? e como crerão naquele de quem não ouviram falar? e como ouvirão, se não há quem pregue?");
    b->dados[ROMANOS].capitulos[10].versos[15] = wxT("E como pregarão, se não forem enviados? assim como está escrito: Quão formosos os pés dos que anunciam coisas boas!");
    b->dados[ROMANOS].capitulos[10].versos[16] = wxT("Mas nem todos deram ouvidos ao evangelho; pois Isaías diz: Senhor, quem deu crédito à nossa mensagem?");
    b->dados[ROMANOS].capitulos[10].versos[17] = wxT("Logo a fé é pelo ouvir, e o ouvir pela palavra de Cristo.");
    b->dados[ROMANOS].capitulos[10].versos[18] = wxT("Mas pergunto: Porventura não ouviram? Sim, por certo: Por toda a terra saiu a voz deles, e as suas palavras até os confins do mundo.");
    b->dados[ROMANOS].capitulos[10].versos[19] = wxT("Mas pergunto ainda: Porventura Israel não o soube? Primeiro diz Moisés: Eu vos porei em ciúmes com aqueles que não são povo, com um povo insensato vos provocarei à ira.");
    b->dados[ROMANOS].capitulos[10].versos[20] = wxT("E Isaías ousou dizer: Fui achado pelos que não me buscavam, manifestei-me aos que por mim não perguntavam.");
    b->dados[ROMANOS].capitulos[10].versos[21] = wxT("Quanto a Israel, porém, diz: Todo o dia estendi as minhas mãos a um povo rebelde e contradizente.");

    b->dados[ROMANOS].capitulos[11].versos[1] = wxT("Pergunto, pois: Acaso rejeitou Deus ao seu povo? De modo nenhum; por que eu também sou israelita, da descendência de Abraão, da tribo de Benjamim.");
    b->dados[ROMANOS].capitulos[11].versos[2] = wxT("Deus não rejeitou ao seu povo que antes conheceu. Ou não sabeis o que a Escritura diz de Elias, como ele fala a Deus contra Israel, dizendo:");
    b->dados[ROMANOS].capitulos[11].versos[3] = wxT("Senhor, mataram os teus profetas, e derribaram os teus altares; e só eu fiquei, e procuraram tirar-me a vida?");
    b->dados[ROMANOS].capitulos[11].versos[4] = wxT("Mas que lhe diz a resposta divina? Reservei para mim sete mil varões que não dobraram os joelhos diante de Baal.");
    b->dados[ROMANOS].capitulos[11].versos[5] = wxT("Assim, pois, também no tempo presente ficou um remanescente segundo a eleição da graça.");
    b->dados[ROMANOS].capitulos[11].versos[6] = wxT("Mas se é pela graça, já não é pelas obras; de outra maneira, a graça já não é graça.");
    b->dados[ROMANOS].capitulos[11].versos[7] = wxT("Pois quê? O que Israel busca, isso não o alcançou; mas os eleitos alcançaram; e os outros foram endurecidos,");
    b->dados[ROMANOS].capitulos[11].versos[8] = wxT("como está escrito: Deus lhes deu um espírito entorpecido, olhos para não verem, e ouvidos para não ouvirem, até o dia de hoje.");
    b->dados[ROMANOS].capitulos[11].versos[9] = wxT("E Davi diz: Torne-se-lhes a sua mesa em laço, e em armadilha, e em tropeço, e em retribuição;");
    b->dados[ROMANOS].capitulos[11].versos[10] = wxT("escureçam-se-lhes os olhos para não verem, e tu encurva-lhes sempre as costas.");
    b->dados[ROMANOS].capitulos[11].versos[11] = wxT("Logo, pergunto: Porventura tropeçaram de modo que caíssem? De maneira nenhuma, antes pelo seu tropeço veio a salvação aos gentios, para os incitar à emulação.");
    b->dados[ROMANOS].capitulos[11].versos[12] = wxT("Ora se o tropeço deles é a riqueza do mundo, e a sua diminuição a riqueza dos gentios, quanto mais a sua plenitude!");
    b->dados[ROMANOS].capitulos[11].versos[13] = wxT("Mas é a vós, gentios, que falo; e, porquanto sou apóstolo dos gentios, glorifico o meu ministério,");
    b->dados[ROMANOS].capitulos[11].versos[14] = wxT("para ver se de algum modo posso incitar à emulação os da minha raça e salvar alguns deles.");
    b->dados[ROMANOS].capitulos[11].versos[15] = wxT("Porque, se a sua rejeição é a reconciliação do mundo, qual será a sua admissão, senão a vida dentre os mortos?");
    b->dados[ROMANOS].capitulos[11].versos[16] = wxT("Se as primícias são santas, também a massa o é; e se a raiz é santa, também os ramos o são.");
    b->dados[ROMANOS].capitulos[11].versos[17] = wxT("E se alguns dos ramos foram quebrados, e tu, sendo zambujeiro, foste enxertado no lugar deles e feito participante da raiz e da seiva da oliveira,");
    b->dados[ROMANOS].capitulos[11].versos[18] = wxT("não te glories contra os ramos; e, se contra eles te gloriares, não és tu que sustentas a raiz, mas a raiz a ti.");
    b->dados[ROMANOS].capitulos[11].versos[19] = wxT("Dirás então: Os ramos foram quebrados, para que eu fosse enxertado.");
    b->dados[ROMANOS].capitulos[11].versos[20] = wxT("Está bem; pela sua incredulidade foram quebrados, e tu pela tua fé estás firme. Não te ensoberbeças, mas teme;");
    b->dados[ROMANOS].capitulos[11].versos[21] = wxT("porque, se Deus não poupou os ramos naturais, não te poupará a ti.");
    b->dados[ROMANOS].capitulos[11].versos[22] = wxT("Considera pois a bondade e a severidade de Deus: para com os que caíram, severidade; para contigo, a bondade de Deus, se permaneceres nessa bondade; do contrário também tu serás cortado.");
    b->dados[ROMANOS].capitulos[11].versos[23] = wxT("E ainda eles, se não permanecerem na incredulidade, serão enxertados; porque poderoso é Deus para os enxertar novamente.");
    b->dados[ROMANOS].capitulos[11].versos[24] = wxT("Pois se tu foste cortado do natural zambujeiro, e contra a natureza enxertado em oliveira legítima, quanto mais não serão enxertados na sua própria oliveira esses que são ramos naturais!");
    b->dados[ROMANOS].capitulos[11].versos[25] = wxT("Porque não quero, irmãos, que ignoreis este mistério {para que não presumais de vós mesmos}: que o endurecimento veio em parte sobre Israel, até que a plenitude dos gentios haja entrado;");
    b->dados[ROMANOS].capitulos[11].versos[26] = wxT("e assim todo o Israel será salvo, como está escrito: Virá de Sião o Libertador, e desviará de Jacó as impiedades;");
    b->dados[ROMANOS].capitulos[11].versos[27] = wxT("e este será o meu pacto com eles, quando eu tirar os seus pecados.");
    b->dados[ROMANOS].capitulos[11].versos[28] = wxT("Quanto ao evangelho, eles na verdade, são inimigos por causa de vós; mas, quanto à eleição, amados por causa dos pais.");
    b->dados[ROMANOS].capitulos[11].versos[29] = wxT("Porque os dons e a vocação de Deus são irretratáveis.");
    b->dados[ROMANOS].capitulos[11].versos[30] = wxT("Pois, assim como vós outrora fostes desobedientes a Deus, mas agora alcançastes misericórdia pela desobediência deles,");
    b->dados[ROMANOS].capitulos[11].versos[31] = wxT("assim também estes agora foram desobedientes, para também alcançarem misericórdia pela misericórdia a vós demonstrada.");
    b->dados[ROMANOS].capitulos[11].versos[32] = wxT("Porque Deus encerrou a todos debaixo da desobediência, a fim de usar de misericórdia para com todos.");
    b->dados[ROMANOS].capitulos[11].versos[33] = wxT("Ó profundidade das riquezas, tanto da sabedoria, como da ciência de Deus! Quão insondáveis são os seus juízos, e quão inescrutáveis os seus caminhos!");
    b->dados[ROMANOS].capitulos[11].versos[34] = wxT("Pois, quem jamais conheceu a mente do Senhor? ou quem se fez seu conselheiro?");
    b->dados[ROMANOS].capitulos[11].versos[35] = wxT("Ou quem lhe deu primeiro a ele, para que lhe seja recompensado?");
    b->dados[ROMANOS].capitulos[11].versos[36] = wxT("Porque dele, e por ele, e para ele, são todas as coisas; glória, pois, a ele eternamente. Amém.");

    b->dados[ROMANOS].capitulos[12].versos[1] = wxT("Rogo-vos pois, irmãos, pela compaixão de Deus, que apresenteis os vossos corpos como um sacrifício vivo, santo e agradável a Deus, que é o vosso culto racional.");
    b->dados[ROMANOS].capitulos[12].versos[2] = wxT("E não vos conformeis a este mundo, mas transformai-vos pela renovação da vossa mente, para que experimenteis qual seja a boa, agradável, e perfeita vontade de Deus.");
    b->dados[ROMANOS].capitulos[12].versos[3] = wxT("Porque pela graça que me foi dada, digo a cada um dentre vós que não tenha de si mesmo mais alto conceito do que convém; mas que pense de si sobriamente, conforme a medida da fé que Deus, repartiu a cada um.");
    b->dados[ROMANOS].capitulos[12].versos[4] = wxT("Pois assim como em um corpo temos muitos membros, e nem todos os membros têm a mesma função,");
    b->dados[ROMANOS].capitulos[12].versos[5] = wxT("assim nós, embora muitos, somos um só corpo em Cristo, e individualmente uns dos outros.");
    b->dados[ROMANOS].capitulos[12].versos[6] = wxT("De modo que, tendo diferentes dons segundo a graça que nos foi dada, se é profecia, seja ela segundo a medida da fé;");
    b->dados[ROMANOS].capitulos[12].versos[7] = wxT("se é ministério, seja em ministrar; se é ensinar, haja dedicação ao ensino;");
    b->dados[ROMANOS].capitulos[12].versos[8] = wxT("ou que exorta, use esse dom em exortar; o que reparte, faça-o com liberalidade; o que preside, com zelo; o que usa de misericórdia, com alegria.");
    b->dados[ROMANOS].capitulos[12].versos[9] = wxT("O amor seja não fingido. Aborrecei o mal e apegai-vos ao bem.");
    b->dados[ROMANOS].capitulos[12].versos[10] = wxT("Amai-vos cordialmente uns aos outros com amor fraternal, preferindo-vos em honra uns aos outros;");
    b->dados[ROMANOS].capitulos[12].versos[11] = wxT("não sejais vagarosos no cuidado; sede fervorosos no espírito, servindo ao Senhor;");
    b->dados[ROMANOS].capitulos[12].versos[12] = wxT("alegrai-vos na esperança, sede pacientes na tribulação, perseverai na oração;");
    b->dados[ROMANOS].capitulos[12].versos[13] = wxT("acudi aos santos nas suas necessidades, exercei a hospitalidade;");
    b->dados[ROMANOS].capitulos[12].versos[14] = wxT("abençoai aos que vos perseguem; abençoai, e não amaldiçoeis;");
    b->dados[ROMANOS].capitulos[12].versos[15] = wxT("alegrai-vos com os que se alegram; chorai com os que choram;");
    b->dados[ROMANOS].capitulos[12].versos[16] = wxT("sede unânimes entre vós; não ambicioneis coisas altivas mas acomodai-vos às humildes; não sejais sábios aos vossos olhos;");
    b->dados[ROMANOS].capitulos[12].versos[17] = wxT("a ninguém torneis mal por mal; procurai as coisas dignas, perante todos os homens.");
    b->dados[ROMANOS].capitulos[12].versos[18] = wxT("Se for possível, quanto depender de vós, tende paz com todos os homens.");
    b->dados[ROMANOS].capitulos[12].versos[19] = wxT("Não vos vingueis a vós mesmos, amados, mas dai lugar à ira de Deus, porque está escrito: Minha é a vingança, eu retribuirei, diz o Senhor.");
    b->dados[ROMANOS].capitulos[12].versos[20] = wxT("Antes, se o teu inimigo tiver fome, dá-lhe de comer; se tiver sede, dá-lhe de beber; porque, fazendo isto amontoarás brasas de fogo sobre a sua cabeça.");
    b->dados[ROMANOS].capitulos[12].versos[21] = wxT("Não te deixes vencer do mal, mas vence o mal com o bem.");

    b->dados[ROMANOS].capitulos[13].versos[1] = wxT("Toda alma esteja sujeita às autoridades superiores; porque não há autoridade que não venha de Deus; e as que existem foram ordenadas por Deus.");
    b->dados[ROMANOS].capitulos[13].versos[2] = wxT("Por isso quem resiste à autoridade resiste à ordenação de Deus; e os que resistem trarão sobre si mesmos a condenação.");
    b->dados[ROMANOS].capitulos[13].versos[3] = wxT("Porque os magistrados não são motivo de temor para os que fazem o bem, mas para os que fazem o mal. Queres tu, pois, não temer a autoridade? Faze o bem, e terás louvor dela;");
    b->dados[ROMANOS].capitulos[13].versos[4] = wxT("porquanto ela é ministro de Deus para teu bem. Mas, se fizeres o mal, teme, pois não traz debalde a espada; porque é ministro de Deus, e vingador em ira contra aquele que pratica o mal.");
    b->dados[ROMANOS].capitulos[13].versos[5] = wxT("Pelo que é necessário que lhe estejais sujeitos, não somente por causa da ira, mas também por causa da consciência.");
    b->dados[ROMANOS].capitulos[13].versos[6] = wxT("Por esta razão também pagais tributo; porque são ministros de Deus, para atenderem a isso mesmo.");
    b->dados[ROMANOS].capitulos[13].versos[7] = wxT("Dai a cada um o que lhe é devido: a quem tributo, tributo; a quem imposto, imposto; a quem temor, temor; a quem honra, honra.");
    b->dados[ROMANOS].capitulos[13].versos[8] = wxT("A ninguém devais coisa alguma, senão o amor recíproco; pois quem ama ao próximo tem cumprido a lei.");
    b->dados[ROMANOS].capitulos[13].versos[9] = wxT("Com efeito: Não adulterarás; não matarás; não furtarás; não cobiçarás; e se há algum outro mandamento, tudo nesta palavra se resume: Amarás ao teu próximo como a ti mesmo.");
    b->dados[ROMANOS].capitulos[13].versos[10] = wxT("O amor não faz mal ao próximo. De modo que o amor é o cumprimento da lei.");
    b->dados[ROMANOS].capitulos[13].versos[11] = wxT("E isso fazei, conhecendo o tempo, que já é hora de despertardes do sono; porque a nossa salvação está agora mais perto de nós do que quando nos tornamos crentes.");
    b->dados[ROMANOS].capitulos[13].versos[12] = wxT("A noite é passada, e o dia é chegado; dispamo-nos, pois, das obras das trevas, e vistamo-nos, pois, das obras das trevas, e vistamo-nos das armas da luz.");
    b->dados[ROMANOS].capitulos[13].versos[13] = wxT("Andemos honestamente, como de dia: não em glutonarias e bebedeiras, não em impudicícias e dissoluções, não em contendas e inveja.");
    b->dados[ROMANOS].capitulos[13].versos[14] = wxT("Mas revesti-vos do Senhor Jesus Cristo; e não tenhais cuidado da carne em suas concupiscências.");

    b->dados[ROMANOS].capitulos[14].versos[1] = wxT("Ora, ao que é fraco na fé, acolhei-o, mas não para condenar-lhe os escrúpulos.");
    b->dados[ROMANOS].capitulos[14].versos[2] = wxT("Um crê que de tudo se pode comer, e outro, que é fraco, come só legumes.");
    b->dados[ROMANOS].capitulos[14].versos[3] = wxT("Quem come não despreze a quem não come; e quem não come não julgue a quem come; pois Deus o acolheu.");
    b->dados[ROMANOS].capitulos[14].versos[4] = wxT("Quem és tu, que julgas o servo alheio? Para seu próprio senhor ele está em pé ou cai; mas estará firme, porque poderoso é o Senhor para o firmar.");
    b->dados[ROMANOS].capitulos[14].versos[5] = wxT("Um faz diferença entre dia e dia, mas outro julga iguais todos os dias. Cada um esteja inteiramente convicto em sua própria mente.");
    b->dados[ROMANOS].capitulos[14].versos[6] = wxT("Aquele que faz caso do dia, para o Senhor o faz. E quem come, para o Senhor come, porque dá graças a Deus; e quem não come, para o Senhor não come, e dá graças a Deus.");
    b->dados[ROMANOS].capitulos[14].versos[7] = wxT("Porque nenhum de nós vive para si, e nenhum morre para si.");
    b->dados[ROMANOS].capitulos[14].versos[8] = wxT("Pois, se vivemos, para o Senhor vivemos; se morremos, para o Senhor morremos. De sorte que, quer vivamos quer morramos, somos do Senhor.");
    b->dados[ROMANOS].capitulos[14].versos[9] = wxT("Porque foi para isto mesmo que Cristo morreu e tornou a viver, para ser Senhor tanto de mortos como de vivos.");
    b->dados[ROMANOS].capitulos[14].versos[10] = wxT("Mas tu, por que julgas teu irmão? Ou tu, também, por que desprezas teu irmão? Pois todos havemos de comparecer ante o tribunal de Deus.");
    b->dados[ROMANOS].capitulos[14].versos[11] = wxT("Porque está escrito: Por minha vida, diz o Senhor, diante de mim se dobrará todo joelho, e toda língua louvará a Deus.");
    b->dados[ROMANOS].capitulos[14].versos[12] = wxT("Assim, pois, cada um de nós dará conta de si mesmo a Deus.");
    b->dados[ROMANOS].capitulos[14].versos[13] = wxT("Portanto não nos julguemos mais uns aos outros; antes o seja o vosso propósito não pôr tropeço ou escândalo ao vosso irmão.");
    b->dados[ROMANOS].capitulos[14].versos[14] = wxT("Eu sei, e estou certo no Senhor Jesus, que nada é de si mesmo imundo a não ser para aquele que assim o considera; para esse é imundo.");
    b->dados[ROMANOS].capitulos[14].versos[15] = wxT("Pois, se pela tua comida se entristece teu irmão, já não andas segundo o amor. Não faças perecer por causa da tua comida aquele por quem Cristo morreu.");
    b->dados[ROMANOS].capitulos[14].versos[16] = wxT("Não seja pois censurado o vosso bem;");
    b->dados[ROMANOS].capitulos[14].versos[17] = wxT("porque o reino de Deus não consiste no comer e no beber, mas na justiça, na paz, e na alegria no Espírito Santo.");
    b->dados[ROMANOS].capitulos[14].versos[18] = wxT("Pois quem nisso serve a Cristo agradável é a Deus e aceito aos homens.");
    b->dados[ROMANOS].capitulos[14].versos[19] = wxT("Assim, pois, sigamos as coisas que servem para a paz e as que contribuem para a edificação mútua.");
    b->dados[ROMANOS].capitulos[14].versos[20] = wxT("Não destruas por causa da comida a obra de Deus. Na verdade tudo é limpo, mas é um mal para o homem dar motivo de tropeço pelo comer.");
    b->dados[ROMANOS].capitulos[14].versos[21] = wxT("Bom é não comer carne, nem beber vinho, nem fazer outra coisa em que teu irmão tropece.");
    b->dados[ROMANOS].capitulos[14].versos[22] = wxT("A fé que tens, guarda-a contigo mesmo diante de Deus. Bem-aventurado aquele que não se condena a si mesmo naquilo que aprova.");
    b->dados[ROMANOS].capitulos[14].versos[23] = wxT("Mas aquele que tem dúvidas, se come está condenado, porque o que faz não provém da fé; e tudo o que não provém da fé é pecado.");

    b->dados[ROMANOS].capitulos[15].versos[1] = wxT("Ora nós, que somos fortes, devemos suportar as fraquezas dos fracos, e não agradar a nós mesmos.");
    b->dados[ROMANOS].capitulos[15].versos[2] = wxT("Portanto cada um de nós agrade ao seu próximo, visando o que é bom para edificação.");
    b->dados[ROMANOS].capitulos[15].versos[3] = wxT("Porque também Cristo não se agradou a si mesmo, mas como está escrito: Sobre mim caíram as injúrias dos que te injuriavam.");
    b->dados[ROMANOS].capitulos[15].versos[4] = wxT("Porquanto, tudo que dantes foi escrito, para nosso ensino foi escrito, para que, pela constância e pela consolação provenientes das Escrituras, tenhamos esperança.");
    b->dados[ROMANOS].capitulos[15].versos[5] = wxT("Ora, o Deus de constância e de consolação vos dê o mesmo sentimento uns para com os outros, segundo Cristo Jesus.");
    b->dados[ROMANOS].capitulos[15].versos[6] = wxT("Para que unânimes, e a uma boca, glorifiqueis ao Deus e Pai de nosso Senhor Jesus Cristo.");
    b->dados[ROMANOS].capitulos[15].versos[7] = wxT("Portanto recebei-vos uns aos outros, como também Cristo nos recebeu, para glória de Deus.");
    b->dados[ROMANOS].capitulos[15].versos[8] = wxT("Digo pois que Cristo foi feito ministro da circuncisão, por causa da verdade de Deus, para confirmar as promessas feitas aos pais;");
    b->dados[ROMANOS].capitulos[15].versos[9] = wxT("e para que os gentios glorifiquem a Deus pela sua misericórdia, como está escrito: Portanto eu te louvarei entre os gentios, e cantarei ao teu nome.");
    b->dados[ROMANOS].capitulos[15].versos[10] = wxT("E outra vez diz: Alegrai-vos, gentios, juntamente com o povo.");
    b->dados[ROMANOS].capitulos[15].versos[11] = wxT("E ainda: Louvai ao Senhor, todos os gentios, e louvem-no, todos os povos.");
    b->dados[ROMANOS].capitulos[15].versos[12] = wxT("E outra vez, diz também Isaías: Haverá a raiz de Jessé, aquele que se levanta para reger os gentios; nele os gentios esperarão.");
    b->dados[ROMANOS].capitulos[15].versos[13] = wxT("Ora, o Deus de esperança vos encha de todo o gozo e paz na vossa fé, para que abundeis na esperança pelo poder do Espírito Santo.");
    b->dados[ROMANOS].capitulos[15].versos[14] = wxT("Eu, da minha parte, irmãos meus, estou persuadido a vosso respeito, que vós já estais cheios de bondade, cheios de todo o conhecimento e capazes, vós mesmos, de admoestar-vos uns aos outros.");
    b->dados[ROMANOS].capitulos[15].versos[15] = wxT("Mas em parte vos escrevo mais ousadamente, como para vos trazer outra vez isto à memória, por causa da graça que por Deus me foi dada,");
    b->dados[ROMANOS].capitulos[15].versos[16] = wxT("para ser ministro de Cristo Jesus entre os gentios, ministrando o evangelho de Deus, para que sejam aceitáveis os gentios como oferta, santificada pelo Espírito Santo.");
    b->dados[ROMANOS].capitulos[15].versos[17] = wxT("Tenho, portanto, motivo para me gloriar em Cristo Jesus, nas coisas concernentes a Deus;");
    b->dados[ROMANOS].capitulos[15].versos[18] = wxT("porque não ousarei falar de coisa alguma senão daquilo que Cristo por meu intermédio tem feito, para obediência da parte dos gentios, por palavra e por obras,");
    b->dados[ROMANOS].capitulos[15].versos[19] = wxT("pelo poder de sinais e prodígios, no poder do Espírito Santo; de modo que desde Jerusalém e arredores, até a Ilíria, tenho divulgado o evangelho de Cristo;");
    b->dados[ROMANOS].capitulos[15].versos[20] = wxT("deste modo esforçando-me por anunciar o evangelho, não onde Cristo houvera sido nomeado, para não edificar sobre fundamento alheio;");
    b->dados[ROMANOS].capitulos[15].versos[21] = wxT("antes, como está escrito: Aqueles a quem não foi anunciado, o verão; e os que não ouviram, entenderão.");
    b->dados[ROMANOS].capitulos[15].versos[22] = wxT("Pelo que também muitas vezes tenho sido impedido de ir ter convosco;");
    b->dados[ROMANOS].capitulos[15].versos[23] = wxT("mas agora, não tendo mais o que me detenha nestas regiões, e tendo já há muitos anos grande desejo de ir visitar-vos,");
    b->dados[ROMANOS].capitulos[15].versos[24] = wxT("eu o farei quando for à Espanha; pois espero ver-vos de passagem e por vós ser encaminhado para lá, depois de ter gozado um pouco da vossa companhia.");
    b->dados[ROMANOS].capitulos[15].versos[25] = wxT("Mas agora vou a Jerusalém para ministrar aos santos.");
    b->dados[ROMANOS].capitulos[15].versos[26] = wxT("Porque pareceu bem à Macedônia e à Acaia levantar uma oferta fraternal para os pobres dentre os santos que estão em Jerusalém.");
    b->dados[ROMANOS].capitulos[15].versos[27] = wxT("Isto pois lhes pareceu bem, como devedores que são para com eles. Porque, se os gentios foram participantes das bênçãos espirituais dos judeus, devem também servir a estes com as materiais.");
    b->dados[ROMANOS].capitulos[15].versos[28] = wxT("Tendo, pois, concluído isto, e havendo-lhes consignado este fruto, de lá, passando por vós, irei à Espanha.");
    b->dados[ROMANOS].capitulos[15].versos[29] = wxT("E bem sei que, quando for visitar-vos, chegarei na plenitude da bênção de Cristo.");
    b->dados[ROMANOS].capitulos[15].versos[30] = wxT("Rogo-vos, irmãos, por nosso Senhor Jesus Cristo e pelo amor do Espírito, que luteis juntamente comigo nas vossas orações por mim a Deus,");
    b->dados[ROMANOS].capitulos[15].versos[31] = wxT("para que eu seja livre dos rebeldes que estão na Judéia, e que este meu ministério em Jerusalém seja aceitável aos santos;");
    b->dados[ROMANOS].capitulos[15].versos[32] = wxT("a fim de que, pela vontade de Deus, eu chegue até vós com alegria, e possa entre vós recobrar as forças.");
    b->dados[ROMANOS].capitulos[15].versos[33] = wxT("E o Deus de paz seja com todos vós. Amém.");

    b->dados[ROMANOS].capitulos[16].versos[1] = wxT("Recomendo-vos a nossa irmã Febe, que é serva da igreja que está em Cencréia;");
    b->dados[ROMANOS].capitulos[16].versos[2] = wxT("para que a recebais no Senhor, de um modo digno dos santos, e a ajudeis em qualquer coisa que de vós necessitar; porque ela tem sido o amparo de muitos, e de mim em particular.");
    b->dados[ROMANOS].capitulos[16].versos[3] = wxT("Saudai a Prisca e a Áqüila, meus cooperadores em Cristo Jesus,");
    b->dados[ROMANOS].capitulos[16].versos[4] = wxT("os quais pela minha vida expuseram as suas cabeças; o que não só eu lhes agradeço, mas também todas as igrejas dos gentios.");
    b->dados[ROMANOS].capitulos[16].versos[5] = wxT("Saudai também a igreja que está na casa deles. Saudai a Epêneto, meu amado, que é as primícias da Ásia para Cristo.");
    b->dados[ROMANOS].capitulos[16].versos[6] = wxT("Saudai a Maria, que muito trabalhou por vós.");
    b->dados[ROMANOS].capitulos[16].versos[7] = wxT("Saudai a Andrônico e a Júnias, meus parentes e meus companheiros de prisão, os quais são bem conceituados entre os apóstolos, e que estavam em Cristo antes de mim.");
    b->dados[ROMANOS].capitulos[16].versos[8] = wxT("Saudai a Ampliato, meu amado no Senhor.");
    b->dados[ROMANOS].capitulos[16].versos[9] = wxT("Saudai a Urbano, nosso cooperador em Cristo, e a Estáquis, meu amado.");
    b->dados[ROMANOS].capitulos[16].versos[10] = wxT("Saudai a Apeles, aprovado em Cristo. Saudai aos da casa de Aristóbulo.");
    b->dados[ROMANOS].capitulos[16].versos[11] = wxT("Saudai a Herodião, meu parente. Saudai aos da casa de Narciso que estão no Senhor.");
    b->dados[ROMANOS].capitulos[16].versos[12] = wxT("Saudai a Trifena e a Trifosa, que trabalham no Senhor. Saudai a amada Pérside, que muito trabalhou no Senhor.");
    b->dados[ROMANOS].capitulos[16].versos[13] = wxT("Saudai a Rufo, eleito no Senhor, e a sua mãe e minha.");
    b->dados[ROMANOS].capitulos[16].versos[14] = wxT("Saudai a Asíncrito, a Flegonte, a Hermes, a Pátrobas, a Hermes, e aos irmãos que estão com eles.");
    b->dados[ROMANOS].capitulos[16].versos[15] = wxT("Saudai a Filólogo e a Júlia, a Nereu e a sua irmã, e a Olimpas, e a todos os santos que com eles estão.");
    b->dados[ROMANOS].capitulos[16].versos[16] = wxT("Saudai-vos uns aos outros com ósculo santo. Todas as igrejas de Cristo vos saúdam.");
    b->dados[ROMANOS].capitulos[16].versos[17] = wxT("Rogo-vos, irmãos, que noteis os que promovem dissensões e escândalos contra a doutrina que aprendestes; desviai-vos deles.");
    b->dados[ROMANOS].capitulos[16].versos[18] = wxT("Porque os tais não servem a Cristo nosso Senhor, mas ao seu ventre; e com palavras suaves e lisonjas enganam os corações dos inocentes.");
    b->dados[ROMANOS].capitulos[16].versos[19] = wxT("Pois a vossa obediência é conhecida de todos. Comprazo-me, portanto, em vós; e quero que sejais sábios para o bem, mas simples para o mal.");
    b->dados[ROMANOS].capitulos[16].versos[20] = wxT("E o Deus de paz em breve esmagará a Satanás debaixo dos vossos pés. A graça de nosso Senhor Jesus Cristo seja convosco.");
    b->dados[ROMANOS].capitulos[16].versos[21] = wxT("Saúdam-vos Timóteo, meu cooperador, e Lúcio, e Jáson, e Sosípatro, meus parentes.");
    b->dados[ROMANOS].capitulos[16].versos[22] = wxT("Eu, Tércio, que escrevo esta carta, vos saúdo no Senhor.");
    b->dados[ROMANOS].capitulos[16].versos[23] = wxT("Saúda-vos Gaio, hospedeiro meu e de toda a igreja. Saúda-vos Erasto, tesoureiro da cidade, e também o irmão Quarto.");
    b->dados[ROMANOS].capitulos[16].versos[24] = wxT("{A graça de nosso Senhor Jesus Cristo seja com todos vós. Amém.}");
    b->dados[ROMANOS].capitulos[16].versos[25] = wxT("Ora, àquele que é poderoso para vos confirmar, segundo o meu evangelho e a pregação de Jesus Cristo, conforme a revelação do mistério guardado em silêncio desde os tempos eternos,");
    b->dados[ROMANOS].capitulos[16].versos[26] = wxT("mas agora manifesto e, por meio das Escrituras proféticas, segundo o mandamento do Deus, eterno, dado a conhecer a todas as nações para obediência da fé;");
    b->dados[ROMANOS].capitulos[16].versos[27] = wxT("ao único Deus sábio seja dada glória por Jesus Cristo para todo o sempre. Amém.");

}
